L.append('function md(s){if(!s)return"";s=s.replace(/./g,function(c){if(c=="&")return"&amp;";if(c=="<")return"&lt;";if(c==">")return"&gt;";return c});s=s.replace(/\\*\\*(.+?)\\*\\*/g,"<strong>$1</strong>");s=s.replace(/`(.+?)`/g,"<code>$1</code>");s=s.replace(/^### (.+)$/gm,"<h3>$1</h3>");s=s.replace(/^(\\d+)\\. (.+)$/gm,"<li>$2</li>");s=s.replace(/^- (.+)$/gm,"<li>$1</li>");s=s.replace(/\\|(.+)\\|/g,function(m){var c=m.slice(1,-1).split("|").map(function(x){return x.trim()});if(c.length<2)return m;if(/^-+$/.test(c[0]))return"";return"<tr>"+c.map(function(x,i){var t=i==0?"th":"td";return"<"+t+">"+x+"</"+t+">"}).join("")+"</tr>"});s=s.replace(/(<tr>.*<\\/tr>\\n?)+/g,"<table>$&</table>");s=s.replace(/\\n{2,}/g,"\\n");return s}')
L.append('async function sendMsg(){var t=inp.value.trim();if(!t||st)return;inp.value="";sbtn.disabled=true;st=true;addMsg("u",esc(t));var td=addTool("正在检索...");var bb=addMsg("a",\'<span class="td"><span></span><span></span><span></span></span>\');var fa="";try{var r=await fetch("/api/agent/chat",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({message:t,thread_id:tid})});if(!r.ok){var e=await r.json().catch(function(){return{detail:r.statusText}});var b=ms.lastElementChild.querySelector(".bb");if(b)b.innerHTML="<span style=\\\"color:#dc2626\\\">抱歉，出错了："+esc(e.detail||e.message||"未知错误")+"</span>";return}var h=r.headers.get("X-Thread-Id");if(h)tid=h;var rd=r.body.getReader(),dc=new TextDecoder(),buf="";while(true){var g=await rd.read();if(g.done)break;buf+=dc.decode(g.value,{stream:true});var ps=buf.split("\\n\\n");buf=ps.pop()||"";for(var pi=0;pi<ps.length;pi++){var bl=ps[pi],ls=bl.split("\\n"),ev="",ds="";for(var li=0;li<ls.length;li++){var ll=ls[li].trim();if(ll.startsWith("event: "))ev=ll.slice(7).trim();else if(ll.startsWith("data: "))ds=ll.slice(6)}if(!ds)continue;try{var da=JSON.parse(ds);if(ev==="tool_start"){var tn=da.name||"";var lb={scenic_spot_search:"查询景点数据库",get_weather:"查询天气",search_food:"搜索美食",plan_itinerary:"规划行程",exchange_rate:"汇率计算"};td.innerHTML=\'<div class="bb"><span class="ts"></span>\'+(lb[tn]||"调用"+tn)+"</div>"}else if(ev==="tool_end"){if(td.parentNode)td.remove()}else if(ev==="token"){fa+=da.text||"";bb.innerHTML=md(fa)+\'<span class="cu"></span>\';sb()}else if(ev==="done"){if(da.thread_id)tid=da.thread_id;if(fa)bb.innerHTML=md(fa);else bb.innerHTML="<span style=\\\"color:var(--muted)\\\">暂无回答</span>"}else if(ev==="error"){bb.innerHTML="<span style=\\\"color:#dc2626\\\">抱歉，出错了："+esc(da.error||"")+"</span>"}}catch(e2){}}}}catch(e3){var b2=ms.lastElementChild.querySelector(".bb");if(b2)b2.innerHTML="<span style=\\\"color:#dc2626\\\">网络错误，请检查连接后重试。</span>"}st=false;sbtn.disabled=!inp.value.trim();inp.focus()}')
L.append('function esc(s){if(!s)return"";var r="";for(var i=0;i<s.length;i++){var c=s[i];if(c=="&")r+="&amp;";else if(c=="<")r+="&lt;";else if(c==">")r+="&gt;";else if(c=="\\n")r+="<br>";else r+=c}return r}')
